const companies = $input.all();
return companies.map(c => ({
  json: {
    company_name: c.json.company_name,
    domain: c.json.domain,
    industry: c.json.industry,
  }
}));

const data = $input.all();
return data.map(item => {
  const company = item.json;
  return {
    json: {
      ...company,
      enrichment: {
        source_a: { status: 'found', confidence: 0.92, employees: Math.floor(Math.random() * 400) + 50 },
        source_b: { status: 'found', confidence: 0.85, decision_makers: ['Head of Sales', 'VP Revenue'] },
        source_c: { status: 'found', confidence: 0.75, tech_stack: ['Salesforce', 'HubSpot'] }
      }
    }
  };
});

const data = $input.all();
return data.map(item => {
  const company = item.json;
  const dm = company.enrichment.source_b.decision_makers;
  const roles = ['Head of Sales', 'VP of Sales', 'VP of Revenue', 'CRO', 'Director of Sales'];
  const firstNames = ['Alex', 'Jordan', 'Taylor', 'Morgan', 'Casey'];
  const lastNames = ['Chen', 'Patel', 'Kim', 'Martinez', 'Johnson'];

  return dm.map((role, i) => {
    const first = firstNames[i % firstNames.length];
    const last = lastNames[i % lastNames.length];
    const email = `${first.toLowerCase()}.${last.toLowerCase()}@${company.domain}`;
    return {
      json: {
        company: company.company_name,
        name: `${first} ${last}`,
        role: role,
        email: email,
        email_score: Math.floor(Math.random() * 20) + 80,
        icp_score: Math.floor(Math.random() * 30) + 70,
        seniority_score: role === 'CRO' ? 100 : role === 'VP of Revenue' ? 95 : 85,
        signal_score: Math.floor(Math.random() * 25) + 75,
      }
    };
  });
}).flat();

const leads = $input.all();
return leads.map(lead => {
  const d = lead.json;
  const composite = Math.round(
    d.icp_score * 0.35 +
    d.seniority_score * 0.25 +
    d.email_score * 0.20 +
    d.signal_score * 0.20
  );

  let list, priority;
  if (composite >= 80) { list = 'Active'; priority = 'High'; }
  else if (composite >= 50) { list = 'Active'; priority = 'Medium'; }
  else if (composite >= 20) { list = 'Nurture'; priority = 'Low'; }
  else { list = 'Excluded'; priority = 'None'; }

  return {
    json: {
      ...d,
      composite_score: composite,
      smartlead_list: list,
      priority: priority,
      personalization: `Hi ${d.name.split(' ')[0]}, noticed ${d.company} is scaling. Would love to connect.`
    }
  };
});

const leads = $input.all();
const active = leads.filter(l => l.json.smartlead_list !== 'Excluded');
return active;
